import type { ConvertibleUnit, FormatDateOptions, FormatOptions, Unit } from '@dynatrace-sdk/units';
/**
 * Shorthands for common datetime display modes that can be used as a `formatter`
 * value on datetime columns instead of full `FormatDateOptions`.
 *
 * - `'date'` — only the date portion (e.g. 3/2/2026).
 * - `'time'` — only the time portion (e.g. 3:47:11 PM).
 * - `'datetime'` — both date and time (e.g. 3/2/2026, 3:47:11 PM).
 *
 * Defaults to `datetime` if no `formatter` is provided on a datetime column.
 *
 * @public
 */
export type DataTableDatetimeDisplayMode = 'date' | 'time' | 'datetime';
/**
 * Options to format a currency (incl. locale and properties accepted by Intl.NumberFormat).
 * @public
 */
export interface FormatterCurrencyOptions extends Omit<Intl.NumberFormatOptions, 'currency' | 'style'> {
    /**
     * The ISO 4217 currency code, such as 'USD' or 'EUR', to which the currency will be formatted.
     */
    currency: Intl.NumberFormatOptions['currency'];
    /**
     * The locale according to which the currency will be formatted.
     */
    locale?: string | string[];
    /**
     * Shortens the number, e.g. 1500 → 1.5k
     */
    abbreviate?: boolean;
}
/**
 * Definition type for the DataTable column definition formatter options
 * @public
 */
export type DataTableCellFormatter = FormatOptions<Unit, ConvertibleUnit> | FormatDateOptions | DataTableDatetimeDisplayMode | FormatterCurrencyOptions;
/**
 * Defines the options passed to the format function.
 * @public
 */
export type DataTableCellFormatterColumnDef = {
    /** Allows formatter options from the `@dynatrace-sdk/units` package to be set. */
    formatter?: DataTableCellFormatter;
};
